    "privacy.rights.body": "Conforme sua localização (incluindo GDPR na UE/EEE e LGPD no Brasil), você pode solicitar acesso, correção, exclusão ou restrição dos seus dados, ou retirar consentimento para analíticos. Escreva para contact@3035tech.com.",
    "privacy.contact.title": "Dúvidas",
    "privacy.contact.body": "Para solicitações de privacidade ou perguntas sobre esta política, envie email para contact@3035tech.com.",
    "privacy.updated": "Última atualização: junho de 2026.",

    // Inner pages
    "pages.backHome": "Voltar ao início",
    "pages.home": "Início",
    "pages.allServices": "Todos os serviços",
    "pages.allCaseStudies": "Todos os casos",
    "pages.service": "Serviço",
